    public List<Integer> leftBottomTraversal(Node node){

        Queue<Node> queue = new LinkedList();

        List<Integer> result = new ArrayList<>();

        if(node == null) return result;

        result.add(node.val);

        if(node.children == null) return result;

        for(Node n : node.children){
            queue.add(n);
        }

        while(!queue.isEmpty()){
            int size = queue.size();

            for(int i = 0; i < size; i++) {
                Node currNode = queue.poll();

                if(i == 0) result.add(0, currNode.val);
                else if(i == size - 1) result.add(currNode.val);

                if(currNode.children == null) continue;

                for(Node n : currNode.children){
                    queue.add(n);
                }
            }
        }

        return result;
    }

}


