// Definition of a Node
struct Node {
    int val;
    vector<Node*> children;

    Node() {}
    Node(int _val) : val(_val) {}
    Node(int _val, vector<Node*> _children) : val(_val), children(_children) {}
};

// Function to perform the left-bottom traversal
vector<int> leftBottomTraversal(Node* node) {
    queue<Node*> queue;
    vector<int> result;

    if (node == nullptr) return result;

    // Add root node value
    result.push_back(node->val);

    if (node->children.empty()) return result;

    // Add children of the root node to the queue
    for (Node* child : node->children) {
        queue.push(child);
    }

    while (!queue.empty()) {
        int size = queue.size();

        for (int i = 0; i < size; i++) {
            Node* currNode = queue.front();
            queue.pop();

            // Add the leftmost node at the beginning of the result
            if (i == 0) result.insert(result.begin(), currNode->val);
            // Add the rightmost node at the end of the result
            else if (i == size - 1) result.push_back(currNode->val);

            // Add children of the current node to the queue
            if (!currNode->children.empty()) {
                for (Node* child : currNode->children) {
                    queue.push(child);
                }
            }
        }
    }

    return result;
}

